import { useEffect, useState } from "react";
import api from "../api";

function Dashboard() {
  const [tasks, setTasks] = useState([]);
  const [title, setTitle] = useState("");

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      const token = localStorage.getItem("token");

      const res = await api.get("/tasks", {
        headers: {
          Authorization: token,
        },
      });

      setTasks(res.data);
    } catch (error) {
      console.log(error);
    }
  };

  const addTask = async () => {
    if (!title.trim()) return;

    try {
      const token = localStorage.getItem("token");

      await api.post(
        "/tasks",
        { title },
        {
          headers: {
            Authorization: token,
          },
        }
      );

      setTitle("");
      fetchTasks();
    } catch (error) {
      console.log(error);
    }
  };

  const completeTask = async (task) => {
    try {
      const token = localStorage.getItem("token");

      await api.put(
        `/tasks/${task._id}`,
        {
          title: task.title,
          completed: true,
        },
        {
          headers: {
            Authorization: token,
          },
        }
      );

      fetchTasks();
    } catch (error) {
      console.log(error);
    }
  };

  const deleteTask = async (id) => {
    try {
      const token = localStorage.getItem("token");

      await api.delete(`/tasks/${id}`, {
        headers: {
          Authorization: token,
        },
      });

      fetchTasks();
    } catch (error) {
      console.log(error);
    }
  };

  const logout = () => {
    localStorage.removeItem("token");
    window.location.href = "/";
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Task Manager Dashboard</h1>

      <button onClick={logout}>
        Logout
      </button>

      <hr />

      <h2>Add Task</h2>

      <input
        type="text"
        placeholder="Task title"
        value={title}
        onChange={(e) =>
          setTitle(e.target.value)
        }
      />

      <button onClick={addTask}>
        Add Task
      </button>

      <hr />

      <h2>My Tasks</h2>

      {tasks.length === 0 ? (
        <p>No tasks found.</p>
      ) : (
        tasks.map((task) => (
          <div
            key={task._id}
            style={{
              border: "1px solid gray",
              padding: "10px",
              marginBottom: "10px",
            }}
          >
            <h3>{task.title}</h3>

            <p>
              Status:
              {" "}
              {task.completed
                ? "Completed ✅"
                : "Pending ⏳"}
            </p>

            {!task.completed && (
              <button
                onClick={() =>
                  completeTask(task)
                }
              >
                Complete
              </button>
            )}

            <button
              onClick={() =>
                deleteTask(task._id)
              }
              style={{
                marginLeft: "10px",
              }}
            >
              Delete
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default Dashboard;
